files.content:
.bt-data-table {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  width: 100%;
  color: var(--text-primary);
  font-family: 'Geist', system-ui, sans-serif;
  font-size: var(--typography-font-size-sm);
  line-height: var(--typography-line-height-xs);
}

.bt-data-table__top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-md);
}

.bt-data-table__title {
  color: var(--text-primary);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-data-table__toolbar {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-sm);
  min-width: 0;
}

.bt-data-table__search {
  width: 180px;
  /* Contain the BTInput clear-button slide animation (translateX 6px)
     so it cannot overflow into adjacent toolbar buttons */
  overflow: hidden;
  border-radius: var(--radius-sm);
}

.bt-data-table__toolbar-icon {
  display: inline-flex;
  width: 16px;
  height: 16px;
  color: currentColor;
}

.bt-data-table__filters {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  min-height: 24px;
  min-width: 0; /* allow inner __filters-scroll to shrink + scroll */
}

/* Horizontally scrollable strip of filter tags.
   flex: 0 1 auto → hug content when it fits, shrink + scroll when it overflows.
   This keeps "Remove All" right next to the last tag with the same gap. */
.bt-data-table__filters-scroll {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  min-width: 0;
  flex: 0 1 auto;
  overflow-x: auto;
  overflow-y: hidden;
  scrollbar-width: thin;
}

.bt-data-table__filters-scroll::-webkit-scrollbar {
  height: 4px;
}

.bt-data-table__filters-scroll::-webkit-scrollbar-thumb {
  background: var(--bg-secondary);
  border-radius: 2px;
}

.bt-data-table__filters-scroll > * {
  flex-shrink: 0;
}


/* .bt-data-table__filters-action replaced by BTButtonLink */

.bt-table-title__sortable {
  cursor: pointer;
  user-select: none;
}

.bt-table-title__sortable:hover {
  background: var(--bg-secondary);
}

.bt-data-table__viewport {
  width: 100%;
  overflow-x: auto;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  --fixed-left-shadow-color: transparent;
  --fixed-right-shadow-color: transparent;
}

.bt-data-table__viewport--scrolled-left {
  --fixed-left-shadow-color: rgba(0, 0, 0, 0.12);
}

.bt-data-table__viewport--scrolled-right {
  --fixed-right-shadow-color: rgba(0, 0, 0, 0.12);
}

.bt-data-table__table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  table-layout: auto;
}


.bt-table-title {
  background: var(--bg-secondary);
}

.bt-data-table--fixed-header .bt-table-title {
  position: sticky;
  top: 0;
  z-index: 4;
}

.bt-table-title--secondary {
  background: var(--color-brand-primary-subtle);
}

.bt-table-title--no-fill {
  background: var(--bg-primary);
}

/* Push background onto <tr> so sticky <th> can inherit it (thead bg doesn't propagate to <tr>).
   --row-bg is also set so sticky cells can use var(--row-bg) instead of fragile `inherit`. */
.bt-table-title tr {
  background: var(--bg-secondary);
  --row-bg: var(--bg-secondary);
}

.bt-table-title--secondary tr {
  background: var(--color-brand-primary-subtle);
  --row-bg: var(--color-brand-primary-subtle);
}

.bt-table-title--no-fill tr {
  background: var(--bg-primary);
  --row-bg: var(--bg-primary);
}

.bt-table-row {
  background: var(--bg-primary);
  --row-bg: var(--bg-primary);
}

.bt-table-row--no-fill {
  background: transparent;
  --row-bg: transparent;
}

.bt-table-row:hover {
  background: var(--bg-secondary);
  --row-bg: var(--bg-secondary);
}

/* ── Tree row children cell — no padding/border so it sits flush ── */
.bt-table-children-row > .bt-table-children-cell {
  padding: 0;
  border-left: 0;
  border-bottom: 0;
}

/* ── Tree expand animation ── */
@keyframes bt-tree-expand-in {
  from { opacity: 0; transform: translateY(-6px); }
  to   { opacity: 1; transform: translateY(0); }
}
.bt-table-children-row {
  animation: bt-tree-expand-in 180ms ease forwards;
}

.bt-table-row--selected {
  background: var(--color-brand-primary-subtle);
  --row-bg: var(--color-brand-primary-subtle);
}

.bt-table-row--selected:hover {
  background: var(--color-brand-primary-subtle);
  --row-bg: var(--color-brand-primary-subtle);
}

.bt-table-item {
  height: 32px;
  padding: 8px;
  border-left: 1px solid var(--border-primary);
  border-bottom: 1px solid var(--border-primary);
  color: var(--text-primary);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  text-align: start;
  vertical-align: middle;
}

/* Column alignment — CSS variable set inline on <td>/<th>, all inner
   flex containers reference it so every cell type is covered automatically. */
.bt-table-item {
  --col-halign: flex-start;
  text-align: start;
}

.bt-table-item:first-child {
  border-left: 0;
}

/* Remove bottom border on last visible row to avoid double line with viewport border.
   Two cases:
   1. Flat table  — last <tr> is a bt-table-row directly
   2. Tree table  — last <tr> is bt-table-children-row; the preceding bt-table-row is the last data row */
tbody tr.bt-table-row:last-child .bt-table-item,
tbody tr.bt-table-row:has(+ tr.bt-table-children-row:last-child) .bt-table-item {
  border-bottom: 0;
}

.bt-table-item--header {
  color: var(--text-primary);
  font-size: var(--typography-font-size-xs);
  font-weight: 600;
  text-transform: uppercase;
}

.bt-table-title--no-fill .bt-table-item--header {
  color: var(--text-secondary);
}

.bt-table-item--no-fill {
  background: transparent;
}



.bt-table-item--tree {
  height: auto;
  padding: 0;
  vertical-align: top;
}

.bt-table-item__content {
  display: flex;
  align-items: center;
  min-width: 0;
  gap: var(--space-xs);
  justify-content: var(--col-halign, flex-start);
}

.bt-table-item__text {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bt-table-item__header-label {
  flex: 1 1 auto;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bt-table-item__sort {
  display: inline-flex;
  width: 16px;
  height: 16px;
  color: var(--icon-tertiary);
  flex: 0 0 auto;
}

.bt-table-item__actions {
  display: inline-flex;
  gap: var(--space-2xs);
  align-items: center;
  justify-content: var(--col-halign, flex-start);
  width: 100%;
}

.bt-table-item__control {
  display: flex;
  width: 100%;
  align-items: center;
  justify-content: var(--col-halign, center);
}

.bt-table-item__option-group {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  min-width: 0;
  justify-content: var(--col-halign, flex-start);
}

.bt-table-item__option {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  min-width: 0;
}

.bt-table-item__field {
  width: 100%;
  min-width: 112px;
}

.bt-table-item__tree {
  display: block;
  min-width: 0;
}

.bt-table-item__tree .bt-tree {
  min-width: 180px;
}

.bt-table-item__tree .bt-tree-item {
  min-height: 24px;
  padding-block: 2px;
}

.bt-table-item__tree .bt-tree-node__children {
  display: none;
}

.bt-table-item__field .bt-input,
.bt-table-item__field .bt-input-dropdown,
.bt-table-item__field .bt-input-multiple-field {
  min-height: 32px;
}

.bt-table-item__badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-rd);
  padding: var(--space-xs) var(--space-sm);
  background: var(--color-ext-success-subtler);
  color: var(--color-ext-success-bold);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  white-space: nowrap;
}

.bt-data-table__fixed-cell {
  position: sticky;
  z-index: 2;
  background: var(--row-bg, var(--bg-primary));
  /* Checkbox column — remove horizontal padding, lock width, always center */
  padding-left: 0;
  padding-right: 0;
  width: 32px;
  min-width: 32px;
  max-width: 32px;
  --col-halign: center;
}

.bt-data-table__fixed-cell--left {
  left: 0;
  border-right: 2px solid var(--border-primary);
}

.bt-data-table__fixed-cell--right {
  right: 0;
  border-left: 2px solid var(--border-primary);
}

.bt-table-title .bt-data-table__fixed-cell {
  z-index: 3;
}

/* Hide native horizontal scrollbar on viewport — replaced by external BTScrollbar */
.bt-data-table__viewport {
  scrollbar-width: none; /* Firefox */
}
.bt-data-table__viewport::-webkit-scrollbar {
  display: none; /* Chrome / Safari / Edge */
}

/* External scrollbar spacer */
.bt-data-table__scrollbar-outer {
  margin-top: 8px;
}

.bt-data-table__pagination {
  display: flex;
  justify-content: stretch;
  width: 100%;
}

/* ── Tree row depth colors (Figma: TableRow states Level 1–5) ─────────── */
.bt-table-row--depth-1 { background: var(--color-l-grey-50);  --row-bg: var(--color-l-grey-50); }
.bt-table-row--depth-2 { background: var(--color-l-grey-100); --row-bg: var(--color-l-grey-100); }
.bt-table-row--depth-3 { background: var(--color-l-grey-150); --row-bg: var(--color-l-grey-150); }
.bt-table-row--depth-4 { background: var(--color-l-grey-200); --row-bg: var(--color-l-grey-200); }
.bt-table-row--depth-5 { background: var(--color-l-grey-300); --row-bg: var(--color-l-grey-300); }

/* Selected overrides depth background */
.bt-table-row--depth-1.bt-table-row--selected,
.bt-table-row--depth-2.bt-table-row--selected,
.bt-table-row--depth-3.bt-table-row--selected,
.bt-table-row--depth-4.bt-table-row--selected,
.bt-table-row--depth-5.bt-table-row--selected {
  background: var(--color-brand-primary-subtle);
  --row-bg: var(--color-brand-primary-subtle);
}

.bt-table-row--depth-1:hover,
.bt-table-row--depth-2:hover,
.bt-table-row--depth-3:hover,
.bt-table-row--depth-4:hover,
.bt-table-row--depth-5:hover {
  background: var(--bg-secondary);
  --row-bg: var(--bg-secondary);
}

/* ── Expander column cell layout ──────────────────────────────────────── */
.bt-table-item__expander-cell {
  display: flex;
  align-items: center;
  gap: 4px;
  min-width: 0;
}

/* expander <td> uses internal indent — override inline padding */
.bt-table-item:has(.bt-table-item__expander-cell) {
  padding-inline: 0;
}

.bt-table-item__expander-indent {
  flex-shrink: 0;
}

.bt-table-item__expander-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  border-radius: var(--radius-xs);
  color: var(--icon-secondary);
  background: transparent;
  border: none;
  padding: 0;
  cursor: pointer;
  transition: transform 0.15s ease, color 0.1s;
}

.bt-table-item__expander-btn:hover {
  color: var(--icon-primary);
}

.bt-table-item__expander-btn--expanded {
  transform: rotate(90deg);
}

.bt-table-item__expander-btn--leaf {
  visibility: hidden;
  pointer-events: none;
}

@media (max-width: 720px) {
  .bt-data-table__top {
    align-items: flex-start;
    flex-direction: column;
  }

  .bt-data-table__toolbar {
    width: 100%;
    justify-content: flex-start;
    flex-wrap: wrap;
  }

  .bt-data-table__search {
    width: min(100%, 240px);
  }
}

import './BTDataTable.css';
import { useCallback, useEffect, useRef, useState } from 'react';
import { BTButton } from '../button/BTButton.js';
import { BTButtonLink } from '../button-link/BTButtonLink.js';
import { BTHint } from '../hint/BTHint.js';
import { BTInputSearch } from '../input-search/BTInputSearch.js';
import { BTPagination } from '../pagination/BTPagination.js';
import { BTScrollbar } from '../scrollbar/BTScrollbar.js';
import { BTTag } from '../tag/BTTag.js';
import { BTTableRow } from './BTTableRow.js';
import { BTTableTitle } from './BTTableTitle.js';
import type {
  BTDataTableCell,
  BTDataTableColumn,
  BTDataTableProps,
  BTDataTableRow,
  BTTableActionPayload,
} from './BTDataTable.types.js';

const DEFAULT_COLUMNS: BTDataTableColumn[] = Array.from({ length: 10 }, (_, index) => ({
  key: `col${index + 1}`,
  label: 'LABEL',
  sortable: true,
}));

const DEFAULT_ROWS: BTDataTableRow[] = Array.from({ length: 10 }, (_, rowIndex) => ({
  id: `row-${rowIndex + 1}`,
  cells: DEFAULT_COLUMNS.reduce<Record<string, BTDataTableCell>>((acc, column) => {
    acc[column.key] = { type: 'text', value: 'Subtext' };
    return acc;
  }, {}),
}));

function titleVariant(variant: string) {
  if (variant === 'secondary') return 'secondary' as const;
  if (variant === 'no-fill') return 'no-fill' as const;
  return 'default' as const;
}

/** Find a row anywhere in the tree by id. */
function findRow(rows: BTDataTableRow[], id: string): BTDataTableRow | null {
  for (const row of rows) {
    if (row.id === id) return row;
    if (row.children?.length) {
      const found = findRow(row.children, id);
      if (found) return found;
    }
  }
  return null;
}

function getAllRowIds(rows: BTDataTableRow[]): string[] {
  const ids: string[] = [];
  for (const row of rows) {
    ids.push(row.id);
    if (row.children?.length) ids.push(...getAllRowIds(row.children));
  }
  return ids;
}

function countAllRows(rows: BTDataTableRow[]): number {
  return rows.reduce((n, r) => n + 1 + countAllRows(r.children ?? []), 0);
}

function rowCheckState(row: BTDataTableRow, sel: string[]): 'checked' | 'indeterminate' | 'unchecked' {
  if (!row.children?.length) return sel.includes(row.id) ? 'checked' : 'unchecked';
  const states = row.children.map((c) => rowCheckState(c, sel));
  if (states.every((s) => s === 'checked')) return 'checked';
  if (states.every((s) => s === 'unchecked')) return 'unchecked';
  return 'indeterminate';
}

function computeHeaderCheckState(rows: BTDataTableRow[], sel: string[]): 'checked' | 'indeterminate' | 'unchecked' {
  if (rows.length === 0) return 'unchecked';
  const states = rows.map((r) => rowCheckState(r, sel));
  if (states.every((s) => s === 'checked')) return 'checked';
  if (states.every((s) => s === 'unchecked')) return 'unchecked';
  return 'indeterminate';
}


function FilterIcon() {
  return (
    <svg viewBox="0 0 16 16" fill="none" aria-hidden="true">
      <path d="M2 3H14L9.33 8.33V13L6.67 14V8.33L2 3Z" fill="currentColor" />
    </svg>
  );
}

export function BTDataTable({
  title = 'Table Title',
  columns = DEFAULT_COLUMNS,
  rows = DEFAULT_ROWS,
  variant = 'default',
  showToolbar = true,
  showFilters = true,
  showPagination = true,
  showSearch = true,
  showFilter = true,
  searchValue = '',
  rowsPerPage = 10,
  rowsPerPageOptions = [10, 20, 50],
  currentPage = 1,
  totalPages = 5,
  filters = ['Filter Active', 'Filter Active', 'Filter Active', 'Filter Active', 'Filter Active'],
  maxVisibleFilters = 4,
  expandedKeys = {},
  maxHeight,
  fixedHeader = false,
  hasCheckbox = false,
  fixedLeft = 0,
  fixedRight = 0,
  selectedRows = [],
  onSearchValueChange,
  onSearchSubmit,
  onPageChange,
  onRowsChange,
  onAction,
  onCellChange,
  onRemoveFilter,
  onRemoveAllFilters,
  onExpandedKeysChange,
  onSort,
  onSelectedRowsChange,
  toolbarActions,
}: BTDataTableProps) {
  const totalRowCount = countAllRows(rows);

  const viewportRef  = useRef<HTMLDivElement>(null);
  const scrollbarRef = useRef<HTMLDivElement>(null);
  const syncingFromViewport  = useRef(false);
  const syncingFromScrollbar = useRef(false);

  const [scrolledLeft,  setScrolledLeft]  = useState(false);
  const [scrolledRight, setScrolledRight] = useState(false);
  const [scrollWidth,   setScrollWidth]   = useState(0);
  const [clientWidth,   setClientWidth]   = useState(0);

  const updateScrollState = useCallback(() => {
    const el = viewportRef.current;
    if (!el) return;
    setScrolledLeft(el.scrollLeft > 0);
    setScrolledRight(el.scrollLeft < el.scrollWidth - el.clientWidth - 1);
    setScrollWidth(el.scrollWidth);
    setClientWidth(el.clientWidth);
  }, []);

  const handleViewportScroll = useCallback(() => {
    updateScrollState();
    if (syncingFromScrollbar.current) return;
    const vp = viewportRef.current;
    const sb = scrollbarRef.current;
    if (!vp || !sb) return;
    syncingFromViewport.current = true;
    sb.scrollLeft = vp.scrollLeft;
    syncingFromViewport.current = false;
  }, [updateScrollState]);

  const handleScrollbarScroll = useCallback(() => {
    if (syncingFromViewport.current) return;
    const vp = viewportRef.current;
    const sb = scrollbarRef.current;
    if (!vp || !sb) return;
    syncingFromScrollbar.current = true;
    vp.scrollLeft = sb.scrollLeft;
    syncingFromScrollbar.current = false;
  }, []);

  useEffect(() => {
    updateScrollState();
    const el = viewportRef.current;
    if (!el) return;
    el.addEventListener('scroll', handleViewportScroll, { passive: true });
    const ro = new ResizeObserver(updateScrollState);
    ro.observe(el);
    return () => {
      el.removeEventListener('scroll', handleViewportScroll);
      ro.disconnect();
    };
  }, [updateScrollState, handleViewportScroll]);

  function handleActionInternal(payload: BTTableActionPayload) {
    if (payload.action === 'check-all') {
      const allIds = getAllRowIds(rows);
      const allSelected = allIds.every((id) => selectedRows.includes(id));
      onSelectedRowsChange?.(allSelected ? [] : allIds);
    } else if (payload.action === 'check-row' && payload.rowId) {
      const target = findRow(rows, payload.rowId);
      // Collect this row + all its descendants
      const affectedIds = target ? getAllRowIds([target]) : [payload.rowId];
      const allAffectedSelected = affectedIds.every((id) => selectedRows.includes(id));
      let next: string[];
      if (allAffectedSelected) {
        // All selected → uncheck all
        next = selectedRows.filter((id) => !affectedIds.includes(id));
      } else {
        // Some or none selected → check all
        const toAdd = affectedIds.filter((id) => !selectedRows.includes(id));
        next = [...selectedRows, ...toAdd];
      }
      onSelectedRowsChange?.(next);
    } else {
      onAction?.(payload);
    }
  }

  return (
    <section
      className={[
        'bt-data-table',
        `bt-data-table--${variant}`,
        fixedHeader && 'bt-data-table--fixed-header',
      ].filter(Boolean).join(' ')}
      data-testid="bt-data-table"
    >
      {/* Header layout (Figma 2373-11585): single row.
          Title (left) · Search + Filter + toolbar actions (right). Filter tags
          live in their own row directly below (.bt-data-table__filters). */}
      <div className="bt-data-table__top">
        <h3 className="bt-data-table__title">{title}</h3>
        {showToolbar && (
          <div className="bt-data-table__toolbar">
            {showSearch && (
              <BTInputSearch
                className="bt-data-table__search"
                value={searchValue}
                placeholder="Search"
                onChange={onSearchValueChange}
                onSearch={(v) => onSearchSubmit?.(v)}
                onClear={() => { onSearchValueChange?.(''); onSearchSubmit?.(''); }}
              />
            )}
            {showFilter && (
              <BTButton
                variant="secondary-light"
                iconOnly
                aria-label="Filter"
                rightIcon={filters.length > 0 ? <BTHint count={filters.length} size="sm" /> : undefined}
                onClick={() => onAction?.({ action: 'filter' })}
              >
                <FilterIcon />
              </BTButton>
            )}
            {toolbarActions}
          </div>
        )}
      </div>

      {showFilters && filters.length > 0 && (
        <div className="bt-data-table__filters">
          {/* Horizontally scrollable strip of filter tags. No "+N" overflow —
              native scroll handles long lists. "Remove All" sits outside the
              scroll area so it's always reachable. */}
          <div className="bt-data-table__filters-scroll">
            {filters.map((filter, index) => (
              <BTTag key={`${filter}-${index}`} label={filter} onRemove={() => onRemoveFilter?.(filter)} />
            ))}
          </div>
          <BTButtonLink label="Remove All" onClick={onRemoveAllFilters} />
        </div>
      )}

      <div
        ref={viewportRef}
        className={[
          'bt-data-table__viewport',
          scrolledLeft  && 'bt-data-table__viewport--scrolled-left',
          scrolledRight && 'bt-data-table__viewport--scrolled-right',
        ].filter(Boolean).join(' ')}
        style={maxHeight ? { maxHeight, overflowY: 'auto' } : undefined}
        onScroll={handleViewportScroll}
      >
        <table className="bt-data-table__table">
          <colgroup>
            {hasCheckbox && <col style={{ width: 32 }} />}
            {columns.map((column) => (
              <col
                key={column.key}
                style={column.fill || !column.width ? undefined : { width: column.width }}
              />
            ))}
          </colgroup>
          <BTTableTitle
            columns={columns}
            variant={titleVariant(variant)}
            hasCheckbox={hasCheckbox}
            fixedLeft={fixedLeft}
            fixedRight={fixedRight}
            selectedRows={selectedRows}
            totalRowCount={totalRowCount}
            headerAllSelected={computeHeaderCheckState(rows, selectedRows) === 'checked'}
            headerSomeSelected={computeHeaderCheckState(rows, selectedRows) === 'indeterminate'}
            onAction={handleActionInternal}
            onSort={onSort}
          />
          <tbody>
            {rows.map((row) => (
              <BTTableRow
                key={row.id}
                row={row}
                columns={columns}
                noFill={variant === 'no-fill'}
                hasCheckbox={hasCheckbox}
                fixedLeft={fixedLeft}
                fixedRight={fixedRight}
                selectedRows={selectedRows}
                totalRowCount={totalRowCount}
                depth={0}
                expandedKeys={expandedKeys}
                onAction={handleActionInternal}
                onCellChange={onCellChange}
                onExpandedKeysChange={onExpandedKeysChange}
              />
            ))}
          </tbody>
        </table>
      </div>

