import './BTDataTable.css';
import { BTTableItem } from './BTTableItem.js';
import { BTCheckbox } from '../checkbox/BTCheckbox.js';
import type { BTDataTableCell, BTDataTableColumn, BTDataTableRow, BTTableRowProps } from './BTDataTable.types.js';

const CHECKBOX_WIDTH = 32;

function cx(...parts: Array<string | false | null | undefined>): string {
  return parts.filter(Boolean).join(' ');
}

/**
 * Recursive tri-state check for a row.
 * Leaf  → checked only if its own ID is in selectedRows.
 * Parent → derived from direct children's states (recursive), never from
 *          whether the parent's own ID is in selectedRows — this keeps
 *          check-by-children consistent with check-by-parent.
 */
function rowCheckState(
  row: BTDataTableRow,
  selectedRows: string[],
): 'checked' | 'indeterminate' | 'unchecked' {
  if (!row.children?.length) {
    return selectedRows.includes(row.id) ? 'checked' : 'unchecked';
  }
  const childStates = row.children.map((c) => rowCheckState(c, selectedRows));
  if (childStates.every((s) => s === 'checked')) return 'checked';
  if (childStates.every((s) => s === 'unchecked')) return 'unchecked';
  return 'indeterminate';
}

function colBaseStyle(col: BTDataTableColumn): React.CSSProperties {
  return col.fill || !col.width
    ? { minWidth: '148px' }
    : { width: col.width, minWidth: col.width, maxWidth: col.width };
}

const HALIGN_MAP = { left: 'flex-start', center: 'center', right: 'flex-end' } as const;

function colAlignStyle(col: BTDataTableColumn): React.CSSProperties {
  if (!col.align || col.align === 'left') return {};
  return {
    '--col-halign': HALIGN_MAP[col.align],
    textAlign: col.align,
  } as React.CSSProperties;
}

function getColWidth(col: BTDataTableColumn | undefined): number {
  if (!col || !col.width) return 148;
  return parseInt(col.width);
}

function stickyStyle(
  effectiveIndex: number,
  columns: BTDataTableColumn[],
  hasCheckbox: boolean,
  fixedLeft: number,
  fixedRight: number,
): React.CSSProperties | undefined {
  const totalCols = (hasCheckbox ? 1 : 0) + columns.length;

  if (fixedLeft > 0 && effectiveIndex < fixedLeft) {
    let left = 0;
    for (let i = 0; i < effectiveIndex; i++) {
      if (i === 0 && hasCheckbox) left += CHECKBOX_WIDTH;
      else {
        const colIdx = hasCheckbox ? i - 1 : i;
        left += getColWidth(columns[colIdx]);
      }
    }
    const isLast = effectiveIndex === fixedLeft - 1;
    return {
      position: 'sticky',
      left: `${left}px`,
      zIndex: 2,
      background: 'var(--row-bg, var(--bg-primary))',
      boxShadow: isLast ? '4px 0 6px -2px var(--fixed-left-shadow-color, transparent)' : undefined,
      transition: isLast ? 'box-shadow 0.2s ease' : undefined,
    };
  }

  if (fixedRight > 0 && effectiveIndex >= totalCols - fixedRight) {
    let right = 0;
    for (let i = effectiveIndex + 1; i < totalCols; i++) {
      if (i === 0 && hasCheckbox) right += CHECKBOX_WIDTH;
      else {
        const colIdx = hasCheckbox ? i - 1 : i;
        right += getColWidth(columns[colIdx]);
      }
    }
    const isFirst = effectiveIndex === totalCols - fixedRight;
    return {
      position: 'sticky',
      right: `${right}px`,
      zIndex: 2,
      background: 'var(--row-bg, var(--bg-primary))',
      boxShadow: isFirst ? '-4px 0 6px -2px var(--fixed-right-shadow-color, transparent)' : undefined,
      transition: isFirst ? 'box-shadow 0.2s ease' : undefined,
    };
  }

  return undefined;
}

const CHEVRON = (
  <svg viewBox="0 0 16 16" fill="none" width="12" height="12" aria-hidden="true">
    <path d="M6 4L10 8L6 12" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

export function BTTableRow({
  row,
  columns,
  noFill = false,
  depth = 0,
  expandedKeys = {},
  hasCheckbox = false,
  fixedLeft = 0,
  fixedRight = 0,
  selectedRows = [],
  onAction,
  onCellChange,
  onExpandedKeysChange,
}: BTTableRowProps) {
  const hasChildren = (row.children?.length ?? 0) > 0;
  const isExpanded = !!expandedKeys[row.id];
  const clampedDepth = Math.min(5, depth);
  const indentWidth = `${depth * 24}px`;
  const levelClass = depth > 0 ? `bt-table-row--depth-${clampedDepth}` : null;
  const checkState = rowCheckState(row, selectedRows);
  // Parent row is "selected" (gets highlight bg) when all its children are checked.
  // Leaf row is selected when its own ID is in selectedRows.
  const isRowSelected = hasChildren ? checkState === 'checked' : selectedRows.includes(row.id);
  const totalCols = (hasCheckbox ? 1 : 0) + columns.length;

  function toggleExpand(e: React.MouseEvent) {
    e.stopPropagation();
    onExpandedKeysChange?.({ ...expandedKeys, [row.id]: !isExpanded });
  }

  const checkboxIsLast = fixedLeft <= 1;
  const checkboxStickyStyle: React.CSSProperties = {
    position: 'sticky',
    left: 0,
    zIndex: 2,
    background: 'var(--row-bg, var(--bg-primary))',
    boxShadow: checkboxIsLast ? '4px 0 6px -2px var(--fixed-left-shadow-color, transparent)' : undefined,
    transition: checkboxIsLast ? 'box-shadow 0.2s ease' : undefined,
  };

  return (
    <>
      <tr className={cx('bt-table-row', levelClass, noFill && 'bt-table-row--no-fill', isRowSelected && 'bt-table-row--selected')}>
        {/* Checkbox cell */}
        {hasCheckbox && (
          <td
            className="bt-table-item bt-data-table__fixed-cell"
            style={{ ...checkboxStickyStyle }}
          >
            <span className="bt-table-item__control">
              <BTCheckbox
                checked={checkState === 'checked'}
                indeterminate={checkState === 'indeterminate'}
                onChange={() => onAction?.({ action: 'check-row', rowId: row.id })}
              />
            </span>
          </td>
        )}

        {columns.map((column, index) => {
          const effectiveIndex = hasCheckbox ? index + 1 : index;
          const fixedStyle = stickyStyle(effectiveIndex, columns, hasCheckbox, fixedLeft, fixedRight);
          const isExpanderCol = !!column.expander;

          if (isExpanderCol) {
            const rawCell = row.cells[column.key];
            const textValue =
              rawCell != null && typeof rawCell === 'object' && 'value' in rawCell
                ? String((rawCell as BTDataTableCell).value ?? '')
                : String(rawCell ?? '');

            const baseStyle = colBaseStyle(column);

            return (
              <td
                key={column.key}
                className="bt-table-item"
                style={{ ...baseStyle, ...colAlignStyle(column), ...fixedStyle }}
              >
                <span className="bt-table-item__expander-cell">
                  <span className="bt-table-item__expander-indent" style={{ width: indentWidth }} />
                  {hasChildren ? (
                    <button
                      type="button"
                      className={cx(
                        'bt-table-item__expander-btn',
                        isExpanded && 'bt-table-item__expander-btn--expanded',
                      )}
                      aria-expanded={isExpanded}
                      aria-label={isExpanded ? 'Collapse row' : 'Expand row'}
                      onClick={toggleExpand}
                    >
                      {CHEVRON}
                    </button>
                  ) : (
                    <span className="bt-table-item__expander-btn bt-table-item__expander-btn--leaf" aria-hidden="true">
                      {CHEVRON}
                    </span>
                  )}
                  <span className="bt-table-item__text">{textValue || 'Subtext'}</span>
                </span>
              </td>
            );
          }

          const baseStyle = colBaseStyle(column);

          return (
            <BTTableItem
              key={column.key}
              as="td"
              cell={row.cells[column.key]}
              columnKey={column.key}
              rowId={row.id}
              noFill={noFill}
              style={{ ...baseStyle, ...colAlignStyle(column), ...fixedStyle }}
              onAction={onAction}
              onCellChange={onCellChange}
            />
          );
        })}
      </tr>

      {hasChildren && isExpanded && (
        <tr className="bt-table-children-row">
          <td colSpan={totalCols} className="bt-table-children-cell">
            <table className="bt-data-table__table">
              <colgroup>
                {hasCheckbox && <col style={{ width: `${CHECKBOX_WIDTH}px` }} />}
                {columns.map((col) => (
                  <col key={col.key} style={col.fill || !col.width ? undefined : { width: col.width }} />
                ))}
              </colgroup>
              <tbody>
                {row.children!.map((child) => (
                  <BTTableRow
                    key={child.id}
                    row={child}
                    columns={columns}
                    noFill={noFill}
                    hasCheckbox={hasCheckbox}
                    fixedLeft={fixedLeft}
                    fixedRight={fixedRight}
                    selectedRows={selectedRows}
                    depth={depth + 1}
                    expandedKeys={expandedKeys}
                    onAction={onAction}
                    onCellChange={onCellChange}
                    onExpandedKeysChange={onExpandedKeysChange}
                  />
                ))}
              </tbody>
            </table>
          </td>
        </tr>
      )}
    </>
  );
}

