  effectiveIndex: number,
  columns: BTDataTableColumn[],
  hasCheckbox: boolean,
  fixedLeft: number,
  fixedRight: number,
): React.CSSProperties | undefined {
  const totalCols = (hasCheckbox ? 1 : 0) + columns.length;

  if (fixedLeft > 0 && effectiveIndex < fixedLeft) {
    let left = 0;
    for (let i = 0; i < effectiveIndex; i++) {
      if (i === 0 && hasCheckbox) left += CHECKBOX_WIDTH;
      else {
        const colIdx = hasCheckbox ? i - 1 : i;
        left += getColWidth(columns[colIdx]);
      }
    }
    const isLast = effectiveIndex === fixedLeft - 1;
    return {
      position: 'sticky',
      left: `${left}px`,
      zIndex: 3,
      background: 'var(--row-bg, var(--bg-primary))',
      boxShadow: isLast ? '4px 0 6px -2px var(--fixed-left-shadow-color, transparent)' : undefined,
      transition: isLast ? 'box-shadow 0.2s ease' : undefined,
    };
  }

  if (fixedRight > 0 && effectiveIndex >= totalCols - fixedRight) {
    let right = 0;
    for (let i = effectiveIndex + 1; i < totalCols; i++) {
      if (i === 0 && hasCheckbox) right += CHECKBOX_WIDTH;
      else {
        const colIdx = hasCheckbox ? i - 1 : i;
        right += getColWidth(columns[colIdx]);
      }
    }
    const isFirst = effectiveIndex === totalCols - fixedRight;
    return {
      position: 'sticky',
      right: `${right}px`,
      zIndex: 3,
      background: 'var(--row-bg, var(--bg-primary))',
      boxShadow: isFirst ? '-4px 0 6px -2px var(--fixed-right-shadow-color, transparent)' : undefined,
      transition: isFirst ? 'box-shadow 0.2s ease' : undefined,
    };
  }

  return undefined;
}

function SortIcon({ direction }: { direction?: BTDataTableSortDirection }) {
  const upOpacity   = direction === 'desc' ? 0.3 : 1;
  const downOpacity = direction === 'asc'  ? 0.3 : 1;
  return (
    <svg viewBox="0 0 16 16" fill="none" aria-hidden="true">
      <path d="M5 6L8 3L11 6H5Z"       fill="currentColor" fillOpacity={upOpacity} />
      <path d="M11 10L8 13L5 10H11Z"   fill="currentColor" fillOpacity={downOpacity} />
    </svg>
  );
}

function TitleCell({
  column,
  fixedStyle,
  onSort,
}: {
  column: BTDataTableColumn;
  fixedStyle?: React.CSSProperties;
  onSort?: (p: BTSortPayload) => void;
}) {
  function handleClick() {
    if (!column.sortable || !onSort) return;
    onSort({ columnKey: column.key, direction: nextDirection(column.sortDirection) });
  }

  const baseStyle = colBaseStyle(column);

  return (
    <th
      className={cx(
        'bt-table-item',
        'bt-table-item--header',
        'bt-table-item--title',
        column.sortable && 'bt-table-title__sortable',
      )}
      scope="col"
      style={{ ...baseStyle, ...colAlignStyle(column), ...fixedStyle }}
      onClick={column.sortable ? handleClick : undefined}
    >
      <span className="bt-table-item__content">
        <span className="bt-table-item__header-label">{column.label}</span>
        <span className="bt-table-item__sort">
          <SortIcon direction={column.sortDirection} />
        </span>
      </span>
    </th>
  );
}

export function BTTableTitle({
  columns,
  variant = 'default',
  hasCheckbox = false,
  fixedLeft = 0,
  fixedRight = 0,
  selectedRows = [],
  totalRowCount = 0,
  headerAllSelected,
  headerSomeSelected,
  onAction,
  onSort,
}: BTTableTitleProps) {
  const allSelected = headerAllSelected ?? (totalRowCount > 0 && selectedRows.length >= totalRowCount);
  const someSelected = headerSomeSelected ?? (selectedRows.length > 0 && !allSelected);

  const checkboxIsLast = fixedLeft <= 1;
  const checkboxStickyStyle: React.CSSProperties = {
    position: 'sticky',
    left: 0,
    zIndex: 3,
    background: 'var(--row-bg, var(--bg-primary))',
    boxShadow: checkboxIsLast ? '4px 0 6px -2px var(--fixed-left-shadow-color, transparent)' : undefined,
    transition: checkboxIsLast ? 'box-shadow 0.2s ease' : undefined,
  };

  return (
    <thead
      className={cx(
        'bt-table-title',
        variant === 'secondary' && 'bt-table-title--secondary',
        variant === 'no-fill' && 'bt-table-title--no-fill',
      )}
    >
      <tr>
        {hasCheckbox && (
          <th
            className="bt-table-item bt-table-item--header bt-data-table__fixed-cell"
            style={{ ...checkboxStickyStyle }}
          >
            <span className="bt-table-item__control">
              <BTCheckbox
                checked={allSelected}
                indeterminate={someSelected}
                onChange={() => onAction?.({ action: 'check-all' })}
              />
            </span>
          </th>
        )}
        {columns.map((column, index) => {
          const effectiveIndex = hasCheckbox ? index + 1 : index;
          const fixedStyle = stickyStyle(effectiveIndex, columns, hasCheckbox, fixedLeft, fixedRight);

          // checkbox-title and title-dropdown go through BTTableItem
          if (column.headerType === 'checkbox-title' || column.headerType === 'title-dropdown') {
            const baseStyle = colBaseStyle(column);
            return (
              <BTTableItem
                key={column.key}
                as="th"
                header
                type={column.headerType}
                label={column.label}
                cell={{ type: column.headerType, label: column.label }}
                columnKey={column.key}
                style={{ ...baseStyle, ...colAlignStyle(column), ...fixedStyle }}
                onAction={onAction}
              />
            );
          }

          // Plain title columns — render directly for sort icon control
          return (
            <TitleCell
              key={column.key}
              column={column}
              fixedStyle={fixedStyle}
              onSort={onSort}
            />
          );
        })}
      </tr>
    </thead>
  );
}

BTTableTitle.displayName = 'BTTableTitle';
